<template>
  <div>
    <a-layout>
      <a-layout-content
        :style="{ background: '#fff', padding: '24px', margin: 0, minHeight: '280px' }"
      >
        <p>
          <a-form layout="inline" :model="param">
            <a-form-item>
              <a-input v-model:value="param.name" placeholder="名称" />
            </a-form-item>
            <a-form-item>
              <a-button type="primary" @click="handleQuery({ page: 1, size: pagination.pageSize })">
                查询
              </a-button>
            </a-form-item>
            <a-form-item>
              <a-button type="primary" @click="add()">
                新增
              </a-button>
            </a-form-item>
          </a-form>
        </p>

        <a-table
          :columns="columns"
          :row-key="record => record.id"
          :data-source="users"
          :pagination="pagination"
          :loading="loading"
          @change="handleTableChange"
        >
          <template #bodyCell="{ column, record }">
            <template v-if="column.dataIndex === 'action'">
              <a-space size="small">
                <!-- 重置密码按钮 -->
                <a-button type="primary" @click="resetPassword(record)">
                  重置密码
                </a-button>
                <a-button type="primary" @click="edit(record)">
                  编辑
                </a-button>
                <a-popconfirm
                  title="删除后不可以恢复，确认删除?"
                  ok-text="是"
                  cancel-text="否"
                  @confirm="handleDelete(record.id)"
                >
                  <a-button type="danger">
                    删除
                  </a-button>
                </a-popconfirm>
              </a-space>
            </template>
          </template>
        </a-table>
      </a-layout-content>
    </a-layout>

    <!-- 新增/编辑弹窗 -->
    <a-modal
      title="用户表单"
      v-model:open="modalVisible"
      :confirm-loading="modalLoading"
      @ok="handleModalOk"
    >
      <a-form :model="user" :label-col="{ span: 6 }" :wrapper-col="{ span: 18 }">
        <a-form-item label="登录名">
          <a-input v-model:value="user.loginName" />
        </a-form-item>
        <a-form-item label="昵称">
          <a-input v-model:value="user.name" />
        </a-form-item>
        <a-form-item label="密码" v-show="!user.id">
          <a-input v-model:value="user.password" />
        </a-form-item>
      </a-form>
    </a-modal>

    <!-- 重置密码弹窗 -->
    <a-modal
      title="重置密码"
      v-model:open="resetModalVisible"
      :confirm-loading="resetModalLoading"
      @ok="handleResetModalOk"
    >
      <a-form :model="user" :label-col="{ span: 6 }" :wrapper-col="{ span: 18 }">
        <a-form-item label="新密码">
          <a-input v-model:value="user.password" type="password" />
        </a-form-item>
      </a-form>
    </a-modal>
  </div>
</template>

<script setup>
/* global hexMd5, KEY */
import axios from 'axios'
import { ref, onMounted } from 'vue'
import { message } from 'ant-design-vue'

// ---------- 数据定义 ----------
const users = ref([])
const param = ref({ name: '' })
const loading = ref(false)
const pagination = ref({
  current: 1,
  pageSize: 2,
  total: 0
})

const columns = [
  { title: '登录名', key: 'loginName', dataIndex: 'loginName' },
  { title: '名称', key: 'name', dataIndex: 'name' },
  { title: '密码', key: 'password', dataIndex: 'password' },
  { title: '操作', key: 'action', dataIndex: 'action' }
]

const modalVisible = ref(false)
const modalLoading = ref(false)
const user = ref({
  id: null,
  loginName: '',
  name: '',
  password: ''
})

// ---------- 重置密码相关 ----------
const resetModalVisible = ref(false)
const resetModalLoading = ref(false)

// ---------- 查询列表 ----------
const handleQuery = (params) => {
  loading.value = true
  axios.get('/user/list', {
    params: {
      page: params.page,
      size: params.size,
      name: param.value.name
    }
  })
    .then((resp) => {
      loading.value = false
      const data = resp.data
      if (data.success) {
        users.value = data.content.list || []
        pagination.value.current = params.page
        pagination.value.total = data.content.total || 0
      } else {
        message.error(data.message || '查询失败')
      }
    })
    .catch(() => {
      loading.value = false
      message.error('查询失败，请重试')
    })
}

// ---------- 分页变化 ----------
const handleTableChange = (paginationInfo) => {
  handleQuery({
    page: paginationInfo.current,
    size: paginationInfo.pageSize
  })
}

// ---------- 新增 ----------
const add = () => {
  modalVisible.value = true
  user.value = {
    id: null,
    loginName: '',
    name: '',
    password: ''
  }
}

// ---------- 编辑 ----------
const edit = (record) => {
  modalVisible.value = true
  user.value = { ...record }
}

// ---------- 删除 ----------
const handleDelete = (id) => {
  console.log('id:', id)
  axios.delete(`/user/delete/${id}`)
    .then((resp) => {
      if (resp.data.success) {
        message.success('删除成功')
        handleQuery({
          page: pagination.value.current,
          size: pagination.value.pageSize
        })
      } else {
        message.error(resp.data.message || '删除失败')
      }
    })
    .catch(() => {
      message.error('删除失败，请重试')
    })
}

// ---------- 保存（新增/更新） ----------
const handleModalOk = () => {
  modalLoading.value = true

  console.log(user.value)
  // 密码 MD5 加密（加盐）
  if (user.value.password) {
    user.value.password = hexMd5(user.value.password + KEY)
  }

  axios.post('/user/save', user.value)
    .then((resp) => {
      const data = resp.data
      if (data.success) {
        modalVisible.value = false
        modalLoading.value = false
        message.success('保存成功')
        handleQuery({
          page: pagination.value.current,
          size: pagination.value.pageSize
        })
      } else {
        modalLoading.value = false
        message.error(data.message || '操作失败')
      }
    })
    .catch(() => {
      modalLoading.value = false
      message.error('保存失败，请重试')
    })
}

// ---------- 重置密码 ----------
const resetPassword = (record) => {
  resetModalVisible.value = true
  user.value = { ...record }
  user.value.password = null // 清空密码框
}

const handleResetModalOk = () => {
  resetModalLoading.value = true

  const password = user.value.password
  // 密码规则：至少包含数字和英文，长度6-32
  const reg = /^(?![0-9]+$)(?![a-zA-Z]+$)[0-9A-Za-z]{6,32}$/
  if (!reg.test(password)) {
    message.error('【密码】至少包含数字和英文，长度6-32')
    resetModalLoading.value = false
    return
  }

  // 加密密码
  const encryptedPassword = hexMd5(password + KEY)

  axios.post('/user/resetPassword', {
    id: user.value.id,
    password: encryptedPassword
  })
    .then((resp) => {
      resetModalLoading.value = false
      const data = resp.data
      if (data.success) {
        resetModalVisible.value = false
        message.success('密码重置成功')
        handleQuery({
          page: pagination.value.current,
          size: pagination.value.pageSize
        })
      } else {
        message.error(data.message || '重置失败')
      }
    })
    .catch(() => {
      resetModalLoading.value = false
      message.error('重置失败，请重试')
    })
}

// ---------- 生命周期 ----------
onMounted(() => {
  handleQuery({
    page: 1,
    size: pagination.value.pageSize
  })
})
</script>

<style scoped>
/* 可自定义样式 */
</style>
